From 2424cec7a099fe4392f052a754fadc28de9f8d86 Mon Sep 17 00:00:00 2001
From: Chen Cohen <chenc@tikalk.com>
Date: Sat, 8 Jul 2017 13:14:05 +0300
Subject: [PATCH] JENKINS-36333 - fix unauthorized Resume build action


diff --git a/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java b/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java
index 50a5030..f73b0ad 100644
--- a/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java
+++ b/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java
@@ -8,6 +8,7 @@ import hudson.model.Queue;
 import hudson.model.Run;
 import jenkins.model.Jenkins;
 import jenkins.model.RunAction2;
+import org.kohsuke.stapler.StaplerProxy;
 import org.kohsuke.stapler.StaplerRequest;
 import org.kohsuke.stapler.StaplerResponse;

@@ -15,7 +16,7 @@ import java.io.IOException;
 import java.util.ArrayList;
 import java.util.List;

-public class MultiJobResumeBuild implements RunAction2 {
+public class MultiJobResumeBuild implements RunAction2, StaplerProxy {

     private final Run<?, ?> run;

@@ -24,7 +25,7 @@ public class MultiJobResumeBuild implements RunAction2 {
     }

     public String getIconFileName() {
-		return "plugin/jenkins-multijob-plugin/tool32.png";
+        return Jenkins.getInstance().hasPermission(Jenkins.ADMINISTER) ? "plugin/jenkins-multijob-plugin/tool32.png" : null;
 	}

     public String getDisplayName() {
@@ -71,4 +72,10 @@ public class MultiJobResumeBuild implements RunAction2 {
         actions.addAll(run.getActions(ParametersAction.class));
         return actions;
     }
+
+    @Override
+    public Object getTarget() {
+        Jenkins.getInstance().checkPermission(Jenkins.ADMINISTER);
+        return this;
+    }
 }
-- 
